import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Setup Wizard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/setup-wizard.md","filePath":"guide/setup-wizard.md"}'),s={name:"guide/setup-wizard.md"};function n(r,e,l,d,p,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="setup-wizard" tabindex="-1">Setup Wizard <a class="header-anchor" href="#setup-wizard" aria-label="Permalink to &quot;Setup Wizard&quot;">​</a></h1><p>The Setup Wizard guides you through configuring SendGrail for the first time. It runs automatically after plugin activation and takes under two minutes to complete.</p><h2 id="accessing-the-wizard" tabindex="-1">Accessing the Wizard <a class="header-anchor" href="#accessing-the-wizard" aria-label="Permalink to &quot;Accessing the Wizard&quot;">​</a></h2><p>The wizard launches automatically when you first visit the SendGrail dashboard and no connections have been configured yet. If you need to run it again, navigate to <code>#/setup-wizard</code> from the SendGrail admin page.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>When the dashboard detects no existing connections, it automatically redirects you to the wizard. This redirect only happens when <code>sendgrail_setup_complete</code> has not been set in your WordPress options.</p></div><h2 id="step-1-welcome" tabindex="-1">Step 1: Welcome <a class="header-anchor" href="#step-1-welcome" aria-label="Permalink to &quot;Step 1: Welcome&quot;">​</a></h2><p>The welcome screen introduces SendGrail and outlines what the wizard will configure. You have two options:</p><ul><li><strong>Continue</strong> -- Proceed to the next step.</li><li><strong>Skip</strong> -- Mark the wizard as complete and go directly to the dashboard. This sets the <code>sendgrail_setup_complete</code> option to <code>true</code>, preventing future auto-redirects.</li></ul><h2 id="step-2-migration" tabindex="-1">Step 2: Migration <a class="header-anchor" href="#step-2-migration" aria-label="Permalink to &quot;Step 2: Migration&quot;">​</a></h2><p>SendGrail scans your WordPress database for settings from other SMTP plugins:</p><ul><li>WP Mail SMTP</li><li>Post SMTP</li><li>FluentSMTP</li><li>Easy WP SMTP</li></ul><p>If settings from any of these plugins are detected, you will see them listed with an <strong>Import</strong> button. Clicking Import creates a new SendGrail connection using the detected credentials.</p><p>If no other SMTP plugins are detected, this step is automatically skipped.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Migration is non-destructive. Your original plugin settings remain untouched in the database. You can safely keep the original plugin deactivated as a backup.</p></div><p>For more details, see the <a href="/guide/migration">Migration</a> page.</p><h2 id="step-3-configure" tabindex="-1">Step 3: Configure <a class="header-anchor" href="#step-3-configure" aria-label="Permalink to &quot;Step 3: Configure&quot;">​</a></h2><p>This is the main configuration step. You will:</p><ol><li><strong>Select a provider</strong> from the dropdown list (Gmail, SendGrid, Amazon SES, etc.). Selecting a provider auto-fills the host, port, and encryption fields with the correct defaults.</li><li><strong>Enter your credentials:</strong><ul><li>From Email</li><li>From Name</li><li>SMTP Username</li><li>SMTP Password (or API key, depending on the provider)</li></ul></li><li><strong>Save</strong> the connection.</li></ol><p>If you imported a connection during the Migration step, the form will be pre-populated with those values for review.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>For providers like Gmail, Yahoo, and Zoho Mail, you must use an <strong>App Password</strong> if two-factor authentication is enabled on your account. Your regular account password will not work.</p></div><h2 id="step-4-test" tabindex="-1">Step 4: Test <a class="header-anchor" href="#step-4-test" aria-label="Permalink to &quot;Step 4: Test&quot;">​</a></h2><p>SendGrail sends a test email through the connection you just configured. Enter a recipient email address and click <strong>Send Test Email</strong>.</p><ul><li><strong>Success</strong> -- A confirmation message appears. The test email should arrive in the recipient&#39;s inbox within seconds.</li><li><strong>Failure</strong> -- An error message is displayed with details about what went wrong (authentication failure, connection timeout, etc.). You can go back to Step 3 to correct your settings.</li></ul><h2 id="step-5-done" tabindex="-1">Step 5: Done <a class="header-anchor" href="#step-5-done" aria-label="Permalink to &quot;Step 5: Done&quot;">​</a></h2><p>The wizard marks setup as complete by saving <code>sendgrail_setup_complete</code> to the WordPress options table. You are presented with:</p><ul><li>A summary of the connection you created.</li><li>A link to the SendGrail dashboard.</li><li>Quick links to configure additional settings like email logging, fallback connections, and notifications.</li></ul><h2 id="the-sendgrail-setup-complete-option" tabindex="-1">The <code>sendgrail_setup_complete</code> Option <a class="header-anchor" href="#the-sendgrail-setup-complete-option" aria-label="Permalink to &quot;The `sendgrail_setup_complete` Option&quot;">​</a></h2><p>This WordPress option (<code>wp_options</code> table) controls the auto-redirect behavior:</p><table tabindex="0"><thead><tr><th>Value</th><th>Behavior</th></tr></thead><tbody><tr><td>Not set</td><td>Dashboard redirects to the Setup Wizard automatically.</td></tr><tr><td><code>true</code></td><td>Dashboard loads normally. Wizard is accessible manually.</td></tr></tbody></table><p>Skipping the wizard or completing it both set this option to <code>true</code>. If you ever want to force the wizard to appear again, delete this option from the database:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DELETE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wp_options </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> option_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sendgrail_setup_complete&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div>',31)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
